#!/usr/bin/env python3
"""Render a Claude Code session JSONL into a human-readable Markdown transcript.

Ground truth is the JSONL; this script produces a lossy, readable view. When
fidelity matters, diff against the sibling .jsonl file.

Usage:
  render-jsonl.py <session.jsonl> [<out.md>]

If <out.md> is omitted, writes to <session>.md next to the JSONL.
"""
from __future__ import annotations

import json
import sys
from pathlib import Path


def block_text(block: dict) -> str:
    t = block.get("type")
    if t == "text":
        return block.get("text", "")
    if t == "tool_use":
        name = block.get("name", "?")
        inp = block.get("input", {})
        # Summarise tool inputs compactly; full payload in JSONL.
        return f"\n\n> **Tool call:** `{name}`\n> ```json\n> {json.dumps(inp, indent=2)[:1500]}\n> ```\n"
    if t == "tool_result":
        content = block.get("content", "")
        if isinstance(content, list):
            content = "\n".join(
                b.get("text", "") for b in content if isinstance(b, dict)
            )
        return f"\n\n> **Tool result:**\n> ```\n> {str(content)[:1500]}\n> ```\n"
    if t == "thinking":
        return ""  # Omit thinking blocks from the readable view.
    return f"<!-- unhandled block type={t} -->"


def message_text(msg) -> str:
    if isinstance(msg, str):
        return msg
    if isinstance(msg, dict):
        content = msg.get("content", "")
        if isinstance(content, str):
            return content
        if isinstance(content, list):
            return "".join(block_text(b) for b in content if isinstance(b, dict))
    return str(msg)


def render(path: Path) -> str:
    lines: list[str] = []
    lines.append(f"# Session transcript: `{path.name}`\n")
    lines.append(
        "> **Rendered view — authoritative source is the sibling `.jsonl` file.**\n"
        "> Tool-use blocks are summarised (input truncated to 1500 chars).\n"
        "> `thinking` blocks are omitted. System / attachment / snapshot records "
        "are omitted.\n"
    )
    turn = 0
    with path.open() as f:
        for raw in f:
            raw = raw.strip()
            if not raw:
                continue
            try:
                rec = json.loads(raw)
            except json.JSONDecodeError:
                continue
            t = rec.get("type")
            ts = rec.get("timestamp", "")
            if t == "user":
                turn += 1
                msg = rec.get("message", {})
                body = message_text(msg).strip()
                if not body:
                    continue
                lines.append(f"\n---\n\n## Turn {turn} — user  <!-- {ts} -->\n\n{body}\n")
            elif t == "assistant":
                msg = rec.get("message", {})
                body = message_text(msg).rstrip()
                if not body:
                    continue
                lines.append(f"\n### Assistant  <!-- {ts} -->\n\n{body}\n")
            # Skip: custom-title, file-history-snapshot, attachment, last-prompt, system
    return "\n".join(lines)


def main(argv: list[str]) -> int:
    if len(argv) < 2:
        print(__doc__, file=sys.stderr)
        return 1
    src = Path(argv[1])
    dst = Path(argv[2]) if len(argv) > 2 else src.with_suffix(".md")
    dst.parent.mkdir(parents=True, exist_ok=True)
    dst.write_text(render(src))
    print(f"wrote {dst} ({dst.stat().st_size} bytes)")
    return 0


if __name__ == "__main__":
    sys.exit(main(sys.argv))

