        body = message_text(rec.get("message", {})).rstrip()
        if not body:
            return None
        return f"\n### Assistant <!-- ts={ts} uuid={uid} -->\n\n{body}\n"
    return None  # Skip system/attachment/snapshot/custom-title/last-prompt.


